(function(){
  var page=document.body?document.body.dataset.page:"";
  var data={
    "settlement-dashboard":{note:"结算总览展示资金路径准备状态，而不是已付款状态。",wallet:[["资金池钱包","0xPool...42","ok"],["出口商收款钱包","0xEXP...21A","ok"],["资金方签名","P0 已禁用","bad"]],proof:[["候选额度","92,000 USDC","ok"],["资金池流动性","620,000 USDC","ok"],["结算路径哈希","0xroute...p0","warn"]],candidate:[["候选对象","RFC-P0-001","ok"],["结算状态","route_ready","warn"],["真实付款","否","bad"]],contract:[["USDC 转账","已禁用","bad"],["银行付款","无","bad"],["审计记录","已准备","ok"]]},
    "settlement-route":{note:"路径页展示 Pool → Exporter 的 USDC 路由，但不触发钱包交易。",wallet:[["Source","0xPool...42","ok"],["Destination","0xEXP...21A","ok"],["Network","demo chain","warn"]],proof:[["Route hash","0xroute...92k","ok"],["Buyer ack","0xack...91b","ok"],["Bank cap","0xcap...92","ok"]],candidate:[["Amount","92,000 USDC","warn"],["Pool pause","false","ok"],["Wallet signature","disabled","bad"]],contract:[["commitLiquidity","preview only","warn"],["transfer USDC","disabled","bad"],["tx hash","none","bad"]]},
    "settlement-reconciliation":{note:"对账页把链上预期、链下记录和审计边界放在一起。",wallet:[["Pool wallet","0xPool...42","ok"],["Exporter wallet","0xEXP...21A","ok"],["Bank account","placeholder","warn"]],proof:[["Expected amount","92,000 USDC","ok"],["Pool tx","none","bad"],["Bank statement","placeholder","warn"]],candidate:[["Audit bundle","0xaudit...001","ok"],["Reconcile status","mock only","warn"],["Mismatch","none because no tx","ok"]],contract:[["Chain event","none","bad"],["Fiat leg","mock","warn"],["Boundary proof","ready","ok"]]},
    "settlement-result":{note:"结算结果页明确记录 route-ready，但没有真实转账、付款或兑换。",wallet:[["Settlement owner","Funder / Platform","warn"],["Exporter wallet","0xEXP...21A","ok"],["Signature status","disabled","bad"]],proof:[["Result receipt","0xsettle...p0","ok"],["Non-execution proof","0xnoTx...p0","ok"],["Audit bundle","0xaudit...001","ok"]],candidate:[["Route state","ready","ok"],["Paid state","not paid","bad"],["Exporter result","readable","ok"]],contract:[["USDC tx","none","bad"],["Bank payment","none","bad"],["Registry write","none","bad"]]}
  };
  var cfg=data[page];
  if(!cfg||document.getElementById("p0-settlement-crypto-rail")||document.getElementById("p0-crypto-rail"))return;
  function st(){if(document.getElementById("p0-settlement-crypto-rail-style"))return;var s=document.createElement("style");s.id="p0-settlement-crypto-rail-style";s.textContent=".settlement-crypto{border:1px solid rgba(52,211,153,.28);background:linear-gradient(135deg,rgba(52,211,153,.10),rgba(56,189,248,.08));border-radius:14px;box-shadow:var(--shadow);overflow:hidden}.settlement-crypto-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.settlement-crypto-card{border:1px solid rgba(159,178,201,.15);background:rgba(7,17,31,.30);border-radius:12px;padding:12px}.settlement-crypto-card h3{margin:0 0 10px;font-size:15px}@media(max-width:1200px){.settlement-crypto-grid{grid-template-columns:1fr}}";document.head.appendChild(s)}
  function badge(k){return k==="ok"?"ok":k==="warn"?"warn":"bad"}
  function rows(a){return a.map(function(r){return'<li><span><span class="small muted">'+r[0]+'</span><br><span class="strong">'+r[1]+'</span></span><span class="badge '+badge(r[2])+'">'+r[2]+'</span></li>'}).join("")}
  function run(){st();var sec=document.createElement("section");sec.id="p0-settlement-crypto-rail";sec.className="section settlement-crypto";sec.innerHTML='<div class="section-head"><div><h2>加密原生结算证明轨迹</h2><p class="section-sub">'+cfg.note+'</p></div><span class="badge ok">USDC rail proof</span></div><div class="content settlement-crypto-grid"><div class="settlement-crypto-card"><h3>钱包 / 账户</h3><ul class="list">'+rows(cfg.wallet)+'</ul></div><div class="settlement-crypto-card"><h3>结算证明</h3><ul class="list">'+rows(cfg.proof)+'</ul></div><div class="settlement-crypto-card"><h3>候选对象状态</h3><ul class="list">'+rows(cfg.candidate)+'</ul></div><div class="settlement-crypto-card"><h3>链上 / 银行状态</h3><ul class="list">'+rows(cfg.contract)+'</ul></div></div>';var rail=document.getElementById("p0-settlement-rail");if(rail&&rail.parentNode){rail.parentNode.insertBefore(sec,rail.nextSibling);return}var hero=document.querySelector(".main .hero");if(hero&&hero.parentNode)hero.parentNode.insertBefore(sec,hero.nextSibling);else document.querySelector(".main")?.prepend(sec)}
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
})();